  {:error, "#{IO.ANSI.red()}Invalid Arc specification
Received: #{inspect(data)}
#{IO.ANSI.yellow()}
The data for an Arc is {radius, angle}
The radius must be >= 0#{IO.ANSI.default_color()}
"}
end

