def validate({mod, param}) do
  name = @name_length |> :crypto.strong_rand_bytes() |> Base.url_encode64(padding: false)
  validate({mod, param, name})
end
def validate({@main_id, nil, @main_id}) do
  {:ok, {@main_id, nil, @main_id}}
end
def validate({mod, param, name})
    when is_atom(mod) and mod != nil and (is_pid(name) or is_atom(name) or is_bitstring(name)) and
           name != nil do
  case mod.validate(param) do
    {:ok, data} -> {:ok, {mod, data, name}}
    err -> err
  end
end
