def validate({width, height, radius})
    when is_number(width) and is_number(height) and is_number(radius) do
  w = abs(width)
  h = abs(height)

  radius =
    case w <= h do
      true -> min(radius, w / 2)
      false -> min(radius, h / 2)
    end

  {:ok, {width, height, radius}}
end
