def verify_recovery_code(
      %User{multi_factor_authentication_settings: %{enabled: true, backup_codes: codes}} = user,
      code
    )
    when is_list(codes) and is_binary(code) do
  hash_code = Enum.find(codes, fn hash -> Pleroma.Password.checkpw(code, hash) end)

  if hash_code do
    MFA.invalidate_backup_code(user, hash_code)
    {:ok, :pass}
  else
    {:error, :invalid_token}
  end
end
def verify_recovery_code(_, _) do
  {:error, :invalid_token}
end

def parse_tag(raw_tag) do
  case is_binary(raw_tag) && Enum.reverse(String.split(raw_tag, ".")) do
    [format | tag] when format in ["rss", "atom"] -> {format, Enum.join(tag, ".")}
    _ -> {"atom", raw_tag}
  end
end

