def handle_event(
      @finch_request_event,
      %{duration: duration},
      %{request: request, result: result},
      config
    ) do
  if request.host == config.remote_host do
    result =
      case result do
        {:ok, %Finch.Response{status: status}} when status >= 200 and status < 300 -> "ok"
        {:ok, %Finch.Response{}} -> "bad_status"
        {:ok, _} -> "stream"
        {:error, %{reason: :timeout}} -> "timeout_error"
        {:error, _} -> "unknown_error"
      end

    :telemetry.execute(
      @persistor_request_event,
      %{duration: duration},
      %{result: result, path: normalize_path(request.path)}
    )
  end

  :ok
end
def handle_event(
      @finch_connect_event,
      %{duration: duration},
      %{host: host} = meta,
      config
    ) do
  if host == config.remote_host do
    :telemetry.execute(
      @persistor_connect_event,
      %{duration: duration},
      %{
        status:
          if meta[:error] do
            "error"
          else
            "ok"
          end
      }
    )
  end

  :ok
end
def handle_event(
      @finch_send_event,
      %{duration: duration},
      %{request: request} = meta,
      config
    ) do
  if request.host == config.remote_host do
    :telemetry.execute(
      @persistor_send_event,
      %{duration: duration},
      %{
        status:
          if meta[:error] do
            "error"
          else
            "ok"
          end
      }
    )
  end

  :ok
end
def handle_event(
      @finch_receive_event,
      %{duration: duration},
      %{request: request} = meta,
      config
    ) do
  if request.host == config.remote_host do
    status = meta[:status] || 0

    :telemetry.execute(
      @persistor_receive_event,
      %{duration: duration},
      %{
        status:
          if meta[:error] || status < 200 || status > 299 do
            "error"
          else
            "ok"
          end
      }
    )
  end

  :ok
end

def find(raw) do
  found =
    Repo.one(
      from(t in Token,
        inner_join: s in Site,
        on: s.id == t.site_id,
        where: t.token_hash == ^Token.hash(raw),
        preload: [:site]
      )
    )

  if found do
    {:ok, found}
  else
    {:error, :not_found}
  end
end

def list(site) do
  Repo.all(
    from(t in Token, where: t.site_id == ^site.id, order_by: [desc: t.inserted_at, desc: t.id])
  )
end

def suggest_keys_to_allow(%Plausible.Site{} = site, limit \\ @max_props) do
  allowed_event_props = site.allowed_event_props || []

  unnested_keys =
    from(e in Plausible.ClickhouseEventV2,
      where: ^Plausible.Sites.site_id_query_filter(site),
      where: fragment("? > (NOW() - INTERVAL 6 MONTH)", e.timestamp),
      select: %{key: fragment("arrayJoin(?)", field(e, :"meta.key"))}
    )

  Plausible.ClickhouseRepo.all(
    from(uk in subquery(unnested_keys),
      where: uk.key not in ^allowed_event_props,
      where: uk.key not in ^@internal_keys,
      group_by: uk.key,
      select: uk.key,
      order_by: {:desc, count(uk.key)},
      limit: ^limit
    )
  )
end

def get_many(%Plausible.Site{} = _site, segment_ids, _opts) when segment_ids == [] do
  {:ok, []}
end
def get_many(%Plausible.Site{} = site, segment_ids, opts) when is_list(segment_ids) do
  fields = Keyword.get(opts, :fields, [:id])

  query =
    from(segment in Segment,
      select: ^fields,
      where: segment.site_id == ^site.id,
      where: segment.id in ^segment_ids
    )

  {:ok, Repo.all(query)}
end

def get_one(user_id, site, site_role, segment_id) do
  if site_role in roles_with_personal_segments() do
    case do_get_one(user_id, site.id, segment_id) do
      %Segment{} = segment -> {:ok, segment}
      nil -> {:error, :segment_not_found}
    end
  else
    {:error, :not_enough_permissions}
  end
end

