def port(major, minor)
    when is_integer(major) and major >= 0 and is_integer(minor) and minor >= 0 do
  :erlang.list_to_port(
    ~c"#Port<" ++ Integer.to_charlist(major) ++ ~c"." ++ Integer.to_charlist(minor) ++ ~c">"
  )
end

def breaks do
  @server |> GenServer.call(:breaks, @timeout) |> Enum.sort()
end

def break(module, function, arity, breaks \\ 1)
    when is_atom(module) and is_atom(function) and arity in 0..255 and is_integer(breaks) and
           breaks >= 0 do
  break_call(
    module,
    function,
    arity,
    quote do
      _
    end,
    breaks
  )
end

def track_remote_object(%Pythonx.Object{resource: ref} = object) when node(ref) == node() do
  {:noop, object}
end
def track_remote_object(%Pythonx.Object{remote_info: gc_notifier} = object)
    when node(gc_notifier) == node() do
  {:noop, object}
end
def track_remote_object(%Pythonx.Object{resource: remote_ref} = object) do
  local_pid = whereis!()
  remote_pid = :erpc.call(node(remote_ref), __MODULE__, :whereis!, [])
  gc_notifier = Pythonx.NIF.create_gc_notifier(local_pid, {:local_gc, remote_pid, remote_ref})
  marker_pid = GenServer.call(remote_pid, {:track, remote_ref, local_pid}, :infinity)
  object = %{object | remote_info: gc_notifier}
  {:ok, object, marker_pid}
end

